/**
 * ForgeCAD Model: Hollow Bottle-Shaped Vase
 * This model is generated by combining cylinders and cones to form a solid vase profile,
 * and then hollowing it out by subtracting an offset inner profile.
 */

// Define parameters as live sliders in the studio
const base_radius = Param.number("Base Radius", 25, { min: 10, max: 100, unit: "mm" });
const base_straight_height = Param.number("Base Straight Height", 5, { min: 1, max: 20, unit: "mm" });
const belly_height = Param.number("Belly Height", 25, { min: 5, max: 100, unit: "mm" });
const belly_radius = Param.number("Belly Radius", 28, { min: 10, max: 100, unit: "mm" });
const shoulder_height = Param.number("Shoulder Height", 45, { min: 10, max: 150, unit: "mm" });
const shoulder_radius = Param.number("Shoulder Radius", 22, { min: 5, max: 100, unit: "mm" });
const neck_height = Param.number("Neck Height Start", 55, { min: 20, max: 200, unit: "mm" });
const neck_radius = Param.number("Neck Radius", 10, { min: 2, max: 50, unit: "mm" });
const total_height = Param.number("Total Height", 65, { min: 30, max: 300, unit: "mm" });
const wall_thickness = Param.number("Wall Thickness", 2, { min: 0.5, max: 5, unit: "mm" });

// Calculate segment heights
const h1 = base_straight_height;
const h2 = belly_height - base_straight_height;
const h3 = shoulder_height - belly_height;
const h4 = neck_height - shoulder_height;
const h5 = total_height - neck_height;

// Construct outer solid segments
const out1 = cylinder(h1, base_radius);
const out2 = cone(h2, base_radius, belly_radius).translate(0, 0, h1);
const out3 = cone(h3, belly_radius, shoulder_radius).translate(0, 0, belly_height);
const out4 = cone(h4, shoulder_radius, neck_radius).translate(0, 0, shoulder_height);
const out5 = cylinder(h5, neck_radius).translate(0, 0, neck_height);

// Union outer segments together to form the exterior of the vase
const outer_solid = out1.union(out2).union(out3).union(out4).union(out5);

// Calculate inner segment dimensions based on wall thickness
const in_r1 = base_radius - wall_thickness;
const in_r2 = belly_radius - wall_thickness;
const in_r3 = shoulder_radius - wall_thickness;
const in_r4 = neck_radius - wall_thickness;
const in_h1 = Math.max(0.1, h1 - wall_thickness);

// Construct inner cutout segments
const in1 = cylinder(in_h1, in_r1).translate(0, 0, wall_thickness);
const in2 = cone(h2, in_r1, in_r2).translate(0, 0, h1);
const in3 = cone(h3, in_r2, in_r3).translate(0, 0, belly_height);
const in4 = cone(h4, in_r3, in_r4).translate(0, 0, shoulder_height);
const in5 = cylinder(h5 + 1, in_r4).translate(0, 0, neck_height);

// Union inner segments to form the solid representation of the hollow interior
const inner_cutout = in1.union(in2).union(in3).union(in4).union(in5);

// Subtract the interior cavity from the exterior shape
const final_vase = outer_solid.subtract(inner_cutout).color("#5f87c6");

// Return the final hollow bottle-shaped vase
return {
  "a-hollow-bottle-shaped-vase,-standing-up": final_vase
};
